const body = $json.body || $json;

// ── Formato WaAPI (web.whatsapp-api.com) ──────────────────────────
if (body.event === 'message' && body.data && body.data.message) {
  const msg = body.data.message;

  // WaAPI usa @lid para cuentas linked-device; extraemos solo el número
  const rawFrom = msg.from || '';
  const phone = rawFrom.replace(/@lid$|@c\.us$/, '');

  return [{ json: {
    phone: phone,
    message: msg.body || '',
    message_id: msg.id ? msg.id.id : '',
    timestamp: String(msg.t || msg.timestamp || ''),
    message_type: msg.type === 'chat' ? 'text' : msg.type,
    is_text: msg.type === 'chat',
    contact_name: msg._data ? msg._data.notifyName : '',
    phone_number_id: body.instanceId || '',
    clinic_id: 'clinic-test'
  }}];
}

// ── Formato Meta WhatsApp Cloud API ──────────────────────────────
const entry = body.entry;
if (!entry || !entry[0] || !entry[0].changes || !entry[0].changes[0] || !entry[0].changes[0].value.messages) {
  return [{ json: { skip: true } }];
}

const value = entry[0].changes[0].value;
const msg = value.messages[0];
const contact = value.contacts ? value.contacts[0] : {};
const phoneNumberId = value.metadata ? value.metadata.phone_number_id : '';

return [{ json: {
  phone: msg.from,
  message: msg.text ? msg.text.body : '',
  message_id: msg.id,
  timestamp: msg.timestamp,
  message_type: msg.type,
  is_text: msg.type === 'text',
  contact_name: contact.profile ? contact.profile.name : '',
  phone_number_id: phoneNumberId,
  clinic_id: 'clinic-test'
}}];

